const formData = $('Webhook').first().json.body.data;
const fieldMap = {};
formData.forEach(field => { if (field.custom_key) { fieldMap[field.custom_key] = field.value; } });
const artworkFields = ['url','title','description','type','year_created','medium','subject','purchase_url'];
const artworks = [];
for (let i = 1; i <= 5; i++) {
  const prefix = `artwork${i}`;
  if (fieldMap[`${prefix}_title`] || fieldMap[`${prefix}_url`]) {
    const artwork = { artwork_number: i };
    artworkFields.forEach(field => {
      const value = fieldMap[`${prefix}_${field}`];
      if (field === 'url' && value && typeof value === 'object') {
        artwork.image_url = value.url; artwork.image_filename = value.name; artwork.image_size = value.size; artwork.image_width = value.width; artwork.image_height = value.height;
      } else { artwork[field] = value || null; }
    });
    artworks.push(artwork);
  }
}
return { artwork_count: artworks.length, artworks, artist: { first_name: fieldMap.first_name, last_name: fieldMap.last_name, email: fieldMap.email, bio: fieldMap.bio } };

